// ── Normalize alert from Netdata, Portainer, or Uptime Kuma ────────
// Each monitoring tool sends a different payload format.
// This node normalizes them into a common structure.

const body = $input.first().json.body || $input.first().json;

let source   = 'unknown';
let title    = 'Monitoring Alert';
let message  = 'No details provided.';
let severity = 'warning';  // 'critical' | 'warning' | 'info' | 'resolved'
let service  = 'unknown';

// ── Uptime Kuma ──────────────────────────────────────────────────────
// Uptime Kuma payload fields: monitorName, status, msg, heartbeat
if (body.monitorName || body.heartbeat) {
  source  = 'Uptime Kuma';
  service = body.monitorName || 'unknown service';
  const isUp = body.heartbeat?.status === 1 || body.status === 'up';
  severity = isUp ? 'resolved' : 'critical';
  title    = `${service} is ${isUp ? 'UP' : 'DOWN'}`;
  message  = body.msg || (isUp ? 'Service recovered.' : 'Service unreachable.');
}

// ── Netdata ──────────────────────────────────────────────────────────
// Netdata webhook payload fields: alarm, status, info, chart
else if (body.alarm || body.chart) {
  source   = 'Netdata';
  service  = body.chart || body.alarm || 'system';
  const netStatus = (body.status || '').toUpperCase();
  severity = netStatus === 'CRITICAL' ? 'critical'
           : netStatus === 'WARNING'  ? 'warning'
           : netStatus === 'CLEAR'    ? 'resolved'
           : 'info';
  title   = `Netdata: ${body.alarm || 'Alert'} — ${netStatus}`;
  message = body.info || `${service}: ${netStatus}`;
}

// ── Portainer ────────────────────────────────────────────────────────
// Portainer webhook body varies; often has container name + event type
else if (body.container || body.event) {
  source  = 'Portainer';
  service = body.container?.Names?.[0]?.replace('/', '') || body.container || 'container';
  const event = (body.event || body.status || 'event').toLowerCase();
  severity = ['die', 'kill', 'oom'].includes(event) ? 'critical'
           : event === 'start' ? 'resolved'
           : 'warning';
  title   = `Container ${service}: ${event}`;
  message = `Event: ${event} on ${service}`;
}

// ── Generic fallback ─────────────────────────────────────────────────
else {
  title   = body.title   || body.summary || 'Monitoring Alert';
  message = body.message || body.body    || JSON.stringify(body).substring(0, 500);
  source  = body.source  || 'monitoring';
  severity = body.severity || body.level || 'warning';
}

const severityEmoji = {
  critical : ':red_circle:',
  warning  : ':large_yellow_circle:',
  info     : ':large_blue_circle:',
  resolved : ':large_green_circle:'
}[severity] || ':grey_question:';

return [{
  json: { source, title, message, severity, service, severityEmoji }
}];
